import React, { useState, useEffect } from 'react';

// 1. DATA STAYS AT THE TOP
const smallChopsData = [
  {
    id: 1,
    name: "The Starter Mark",
    price: "15,000",
    contents: "7 Samosas, 7 Spring rolls, 15 Puff Puff, 10 Mosa (or 5 Money Bags), 4 Chicken",
    image: "/images/starter.jpg" 
  },
  {
    id: 2,
    name: "Signature Platter",
    price: "25,000",
    contents: "10 Spring rolls, 10 Samosas, 25 Puff Puff, 20 Mosa (or 15 Money Bags), 8 Chicken. Our curated selection for gifting & luxury sharing.",
    image: "/images/signature.jpg" 
  },
  {
    id: 3,
    name: "Owambe Platter",
    price: "150,000",
    contents: "Full Event Catering service for 50 People. The ultimate party selection for luxury gatherings.",
    image: "/images/owambe.jpg" 
  },
  {
    id: 4,
    name: "Customized Platter",
    price: "200,000",
    contents: "Bespoke catering tailored to your specific party guest list and cravings. Starts at ₦200k.",
    image: "/images/custom.jpg" 
  }
];

const lunchMenu = [
  { day: "Monday", meal: "Signature Jollof Rice & Chicken (Delivery Included)", price: 4500, protein: "Standard" },
  { day: "Tuesday", meal: "Ewa Agoyin + Bread/Plantain", price: 2500, protein: "Optional (+1000)" },
  { day: "Wednesday", meal: "White Rice & Stew + Egg", price: 2000, protein: "With Protein (+1000)" },
  { day: "Thursday", meal: "Spaghetti Stir-fry + Chicken & Egg", price: 4000, protein: "Standard" },
  { day: "Friday", meal: "Amala & Ewedu + Assorted or Mini Small Chops", price: 4000, protein: "Standard" }
];

const quotes = [
  "You’re doing big things today. Take 20 minutes to refuel.",
  "Hard work looks good on you, but so does a premium lunch.",
  "Hustle is good, but lunch is better. Relax, we've got the kitchen.",
  "One meal at a time, one goal at a time. Keep chasing the vision."
];

// 2. MAIN MENU COMPONENT
function Menu() {
  return (
    <section style={{ backgroundColor: '#000', color: '#fff', padding: '80px 20px', fontFamily: 'Arial, sans-serif' }}>
      <h2 style={{ color: '#D4AF37', textAlign: 'center', letterSpacing: '10px', textTransform: 'uppercase', fontSize: '2rem', marginBottom: '60px', fontWeight: '300' }}>
        The Collections
      </h2>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', justifyContent: 'center', gap: '40px', maxWidth: '1300px', margin: '0 auto' }}>
        {smallChopsData.map((pack) => (
          <div key={pack.id} style={{ backgroundColor: '#0A0A0A', borderRadius: '0px', overflow: 'hidden', border: '1px solid #1A1A1A', display: 'flex', flexDirection: 'column', transition: 'transform 0.3s ease' }}>
            <div style={{ width: '100%', height: '280px', overflow: 'hidden' }}>
                <img src={pack.image} alt={pack.name} style={{ width: '100%', height: '100%', objectFit: 'cover', filter: 'brightness(0.9) contrast(1.1)' }} 
                  onError={(e) => { e.target.src = "https://via.placeholder.com/400x300/111/D4AF37?text=Ami+By+T"; }} />
            </div>
            <div style={{ padding: '25px', flexGrow: 1, display: 'flex', flexDirection: 'column', justifyContent: 'space-between' }}>
              <div>
                <h3 style={{ color: '#D4AF37', fontSize: '1.4rem', marginBottom: '15px', textTransform: 'uppercase', letterSpacing: '2px' }}>{pack.name}</h3>
                <p style={{ color: '#ccc', fontSize: '0.85rem', lineHeight: '1.6', marginBottom: '25px', borderLeft: '1px solid #D4AF37', paddingLeft: '15px', minHeight: '60px' }}>
                  {pack.contents}
                </p>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 'auto' }}>
                <p style={{ color: '#fff', fontSize: '1.5rem', fontWeight: 'bold', margin: 0 }}>₦{pack.price}</p>
                <button style={{ backgroundColor: 'transparent', color: '#D4AF37', border: '1px solid #D4AF37', padding: '10px 20px', fontSize: '0.75rem', fontWeight: 'bold', textTransform: 'uppercase', letterSpacing: '2px', cursor: 'pointer' }}>
                  Book Now
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>
      {/* Note: Ensure OfficeLunchSection is defined or imported */}
      {typeof OfficeLunchSection !== 'undefined' && <OfficeLunchSection />}
    </section>
  );
}

// 3. LUNCH COMPONENT
function Lunch() {
  const [quote, setQuote] = useState("");

  useEffect(() => {
    setQuote(quotes[Math.floor(Math.random() * quotes.length)]);
  }, []);

  return (
    <section style={{ backgroundColor: '#000', color: '#fff', padding: '60px 20px', fontFamily: 'Arial, sans-serif' }}>
      <div style={{ textAlign: 'center', padding: '20px', color: '#D4AF37', border: '1px solid #D4AF37', marginBottom: '40px', fontStyle: 'italic' }}>
        "{quote}"
      </div>

      <h2 style={{ color: '#D4AF37', textAlign: 'center', letterSpacing: '5px', textTransform: 'uppercase' }}>Office Lunch Subscriptions</h2>

      <div style={{ margin: '40px auto', maxWidth: '800px', border: '1px solid #1A1A1A', borderRadius: '8px', overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
          <thead style={{ backgroundColor: '#1A1A1A', color: '#D4AF37' }}>
            <tr>
              <th style={{ padding: '15px' }}>Plan</th>
              <th style={{ padding: '15px' }}>Price</th>
              <th style={{ padding: '15px' }}>Benefit</th>
            </tr>
          </thead>
          <tbody>
            <tr style={{ borderBottom: '1px solid #1A1A1A' }}>
              <td style={{ padding: '15px' }}>Weekly Executive</td>
              <td style={{ padding: '15px' }}>₦16,000</td>
              <td style={{ padding: '15px', color: '#00FF00' }}>Save ₦3,000/week</td>
            </tr>
            <tr style={{ borderBottom: '1px solid #1A1A1A', backgroundColor: '#0A0A0A' }}>
              <td style={{ padding: '15px', fontWeight: 'bold' }}>Monthly Corporate ✨</td>
              <td style={{ padding: '15px', fontWeight: 'bold' }}>₦58,000</td>
              <td style={{ padding: '15px', color: '#D4AF37' }}>Save ₦18,000/month</td>
            </tr>
          </tbody>
        </table>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px', maxWidth: '1200px', margin: '0 auto' }}>
        {lunchMenu.map((item, index) => (
          <div key={index} style={{ padding: '20px', border: '1px solid #1A1A1A', backgroundColor: '#050505' }}>
            <h4 style={{ color: '#D4AF37', marginBottom: '10px' }}>{item.day}</h4>
            <p style={{ fontSize: '0.9rem', color: '#ccc' }}>{item.meal}</p>
            <p style={{ fontWeight: 'bold', marginTop: '10px' }}>₦{item.price}</p>
            <p style={{ fontSize: '0.7rem', color: '#666' }}>{item.protein}</p>
          </div>
        ))}
      </div>

      <div style={{ textAlign: 'center', marginTop: '40px' }}>
         <p style={{ color: '#D4AF37' }}>Add Cold Zobo: ₦1,000</p>
         <button style={{ backgroundColor: '#D4AF37', color: '#000', border: 'none', padding: '15px 40px', fontWeight: 'bold', cursor: 'pointer', marginTop: '20px' }}>
            SUBSCRIBE NOW
         </button>
      </div>
    </section>
  );
}

